mapper.update:
UPDATE reservation
reader_id = #{readerId}, book_id = #{bookId}, seat_id = #{seatId}, reservation_date = #{reservationDate}, status = #{status}, expiry_date = #{expiryDate},
WHERE id = #{id}

mapper.select:
SELECT DISTINCT seat_id FROM reservation
WHERE seat_id IS NOT NULL
  AND preferred_time_slot = #{timeSlot}
  AND DATE(reservation_date) = #{date}
  AND status IN (0, 1)
